12: // EnvironmentStore is the minimal abstraction for interacting with the storage layer for evaluation.
13: type EnvironmentStore interface {
14: 	GetFromContext(context.Context) (environments.Environment, error)
15: 	Get(context.Context, string) (environments.Environment, error)
16: }
17: 
18: // Server serves the Flipt evaluate v2 gRPC Server.
19: type Server struct {
20: 	logger         *zap.Logger
21: 	store          EnvironmentStore
22: 	tracingEnabled bool
23: 	evaluation.UnimplementedEvaluationServiceServer
24: }
25: 
26: // Option is a functional option for configuring the Server.
27: type Option func(*Server)
28: 
29: // WithTracing enables telemetry for the evaluation server.
30: func WithTracing(enabled bool) Option {
31: 	return func(s *Server) {
32: 		s.tracingEnabled = enabled
33: 	}
34: }
35: 
36: // New is constructs a new Server.
37: func New(logger *zap.Logger, store EnvironmentStore, ops ...Option) *Server {
38: 	s := &Server{
39: 		logger: logger,
40: 		store:  store,
41: 	}
42: 
43: 	for _, o := range ops {
44: 		o(s)
45: 	}
46: 
47: 	return s
48: }
49: 
50: // RegisterGRPC registers the EvaluateServer onto the provided gRPC Server.
51: func (s *Server) RegisterGRPC(server *grpc.Server) {
52: 	evaluation.RegisterEvaluationServiceServer(server, s)
53: }
54: 
55: func (s *Server) SkipsAuthorization(ctx context.Context) bool {
56: 	return true
57: }
